// 1. Obtenemos el objeto principal
const item = items[0].json;

// 2. Navegamos por la estructura específica: content -> parts[0] -> text
let rawResponse = "";

if (item.content && item.content.parts && item.content.parts[0] && item.content.parts[0].text) {
    rawResponse = item.content.parts[0].text;
} else {
    // Backup por si la estructura cambia o viene de otro modo
    rawResponse = item.text || item.output || (typeof item.content === 'string' ? item.content : "");
}

try {
    // 3. Limpieza de Markdown (quitar bloques ```json ... ```)
    let cleanString = rawResponse
        .replace(/```json/gi, '') 
        .replace(/```/g, '')      
        .trim();

    // 4. Parsear el JSON interno
    const parsedData = JSON.parse(cleanString);

    // 5. Devolvemos el objeto para que n8n vea los campos (fecha, monto, etc.)
    return [{ json: parsedData }];

} catch (error) {
    // Si falla el parseo, devolvemos el texto plano para no perder la info
    return [{ 
        json: { 
            error: "No se pudo parsear el JSON",
            raw_text: rawResponse 
        } 
    }];
}

