const categorias = $input.all().map(item => item.json);

const listaCategoriasTexto = categorias.map(c => 
  `- ID: ${c.id} | Nombre: ${c.nombre} | Tipo: ${c.tipo}`
).join('\n');

return [{
  json: {
    categorias_texto: listaCategoriasTexto,
    descripcion_gasto: $('Edit Fields').first().json.descripcion,
    monto: $('Edit Fields').first().json.monto_original
  }
}];

// Obtenemos los datos que llegaron del Webhook
const data = $input.item.json.body;

// Función auxiliar para formatear moneda ARS
const formatoMoneda = (monto) => {
  if (monto === undefined || monto === null) return "$ 0,00";
  return new Intl.NumberFormat('es-AR', {
    style: 'currency',
    currency: 'ARS'
  }).format(monto);
};

// Función auxiliar para formatear fecha de YYYY-MM-DD a DD/MM/YYYY
const formatoFecha = (fechaStr) => {
  if (!fechaStr) return "";
  const [year, month, day] = fechaStr.split('-');
  return `${day}/${month}/${year}`;
};

// Limpiamos y estructuramos un nuevo objeto armadito para el HTML
const ordenDePago = {
  id: data.op_id,
  numero_op: data.numero_op || "Sin Número",
  proveedor_id: data.proveedor_id,
  tenant_id: data.tenant_id, // <-- ¡Acá agregamos el tenant_id para que pase al resto de los nodos!
  fecha: formatoFecha(data.fecha),
  observaciones: data.observaciones || "Sin observaciones",

  // Montos ya formateados listos para imprimir en HTML (ej: "$ 150.000,00")
  monto_bruto_str: formatoMoneda(data.monto_bruto),
  monto_retenciones_str: formatoMoneda(data.monto_retenciones),
  monto_neto_str: formatoMoneda(data.monto_neto),

  // Montos matematicos puros por si necesitas hacer cálculos despues
  bruto_num: Number(data.monto_bruto || 0),
  retenciones_num: Number(data.monto_retenciones || 0),
  neto_num: Number(data.monto_neto || 0)
};

// Devolvemos el item limpio para el siguiente nodo (Edit Fields)
return {
  json: ordenDePago
};

const text = $json.message.text; // "/vincular ANTI-4X7K"
const code = text.split(' ')[1]?.trim().toUpperCase();
const chat_id = String($json.message.chat.id);
const username = $json.message.from?.username 
  ? '@' + $json.message.from.username 
  : $json.message.from?.first_name || '';

return [{ json: { code, chat_id, username } }];

const item = $input.first();
const binary = item.binary.data0;

if (binary.fileName && binary.fileName.endsWith('.pdf')) {
  binary.mimeType = 'application/pdf';
} else {
  binary.mimeType = 'image/jpeg';
}

return [{
  json: item.json,
  binary: { data0: binary }
}];

